import functools


class Solution:
    def minimumMoves(self, s):
        n = len(s)

        @functools.lru_cache(maxsize=None)
        def solve(i):
            if i >= n:
                return 0
            if s[i] == 'O':
                return solve(i + 1)
            return 1 + solve(i + 3)

        return solve(0)

